notes:
If you are on Arch or Manjaro, install xboxdrv, faudio, and lib32-faudio. To fix audio, run
ln -sf /usr/lib/libFAudio.so.0 ~/steam/steamapps/common/Proton 4.2/dist/lib/libFAudio.so.0.19.04;
ln -sf /usr/lib64/libFAudio.so.0 ~/steam/steamapps/common/Proton 4.2/dist/lib64/libFAudio.so.0.19.04;
To stop the game from closing after 5 minutes, plug in a controller or run
sudo systemctl enable xboxdrv && sudo systemctl start xboxdrv;

/* UBUNTU 18.04 / 19.04 < testet */

/* if not update you System */

$ sudo apt install update ##

$ sudo apt install upgrade ##

$ restart # if needet ##

/* Go home */

$ cd ##

/* 1.0 Update you'r Driver */

/* 1.1 NVIDEA */

$ sudo add-apt-repository ppa:graphics-drivers/ppa ##

$ sudo apt install nvidia-driver-430 ##

/* 1.2 AMD */

$ sudo add-apt-repository ppa:paulo-miguel-dias/pkppa ##

$ sudo apt dist-upgrade ##

$ sudo apt install mesa-vulkan-drivers mesa-vulkan-drivers:i386 ##

/* 1.3 restart */

$ restart ##

/* 2.0 Install Steam and tools */

$ sudo apt install steam steam-devices xz-utils curl tar gzip wine64-tools ##

/* 2.1 Downloade Activate Proton in Steam */

/* Start Steam */

$ steam ##

/* Go to Menu > Steam > Settings > Account > CHANGE.... > Steam Beta Update */

/* Go to Menu > Steam > Settings > Steam Play > Enable Steam Play for supported titles >> ON */

/* Go to Menu > Steam > Settings > Steam Play > Enable Steam Play for all other titles >> ON > Run other titles with: Select Newest */ 

/* Restart Steam */

/* Download Warframe */

$ steam steam://install/230410 ##

/* Finish Proton and Warframe Downloade */

/* 2.2 Install xboxdrv if you NOT use Controller */

$ curl -O https://gist.githubusercontent.com/xarvh/6abfbd176a48e21886813e98480e9dc5/raw/96642aeea1a1f59d9f59cff5b6ecbb20362fdfd3/xboxdrv.service ##

$ sudo apt install xboxdrv ##

$ sudo mv xboxdrv.service /etc/systemd/system ##

$ sudo systemctl enable xboxdrv ##

$ sudo systemctl start xboxdrv ##

/* 3.0 Install costum Proton */

$ mkdir /.steam/root/compatibilitytools.d ##

$ wget -q --show progress https://github.com/GloriousEggroll/proton-ge-custom/releases/download/4.11-GE-1/Proton-4.11-GE-1.tar.gz ##

$ tar -xzf ~/Proton-4.11-GE-1.tar.gz -C ~/.steam/root/compatibilitytools.d ##

$ killall steam ##

$ steam ##

/* 4.0 Activate GE-Proton for Warframe */

/* Go to LIBRARY > Right klick on Warframe > Properties > GENERAL > SET LAUNCH OPTIONS.... */

/* Copy and Past */

/* WINEDLLOVERRIDES="xaudio2_7=n,b" %command% */

/* > OK */

/* Go to LIBRARY > Right klick on Warframe > Properties > GENERAL > Select: Forece the use of spac.... > Proton-4.11-GE-1 -> Close */

/* install xact */

$ WINEPREFIX=~/.steam/steam/steamapps/compatdata/230410/pfx winetricks xact ##

$ steam steam://run/230410 ##

/* Enjoy the Game */

/* The first times you run it, the CPU will be busy compiling shaders and your framerate will drop periodically. */

